// File Validation with Enhanced Error Handling
const items = $input.all();
const validatedItems = [];

for (const item of items) {
  try {
    console.log(item)
    const binary = item.binary;

    // Check if file exists
    if (!binary || !binary['Upload_PDF_File']) {
      throw new Error('No file uploaded. Please select a PDF file.');
    }

    const file = binary['Upload_PDF_File'];

    // Validate MIME type
    const validTypes = ['application/pdf'];
    if (!validTypes.includes(file.mimeType)) {
      throw new Error(`Invalid file type: ${file.mimeType}. Only PDF files are accepted.`);
    }

    // Validate file size (max 50MB)
    const maxSize = 50 * 1024 * 1024;
    const fileSize = Buffer.byteLength(file.data, 'base64');

    if (fileSize > maxSize) {
      const sizeMB = (fileSize / 1024 / 1024).toFixed(2);
      throw new Error(`File too large: ${sizeMB} MB. Maximum allowed size is 50MB.`);
    }
    // Validate file is not empty
    if (fileSize <= 0) {
      throw new Error('File appears to be empty or corrupted.');
    }

    // Add metadata
    item.json.fileSize = fileSize;
    item.json.fileSizeMB = (fileSize / 1024 / 1024).toFixed(2);
    item.json.fileName = file.fileName || 'uploaded.pdf';
    item.json.uploadTime = new Date().toISOString();
    item.json.validationStatus = 'passed';
    item.json.outputFormat = item.json['Output Format'] || 'Both (TXT + CSV)';

    // Normalize binary data field name
    item.binary.data = file;
    item.json.success= true;

    validatedItems.push(item);

  } catch (error) {
    // Return error in standardized format
    console.log(error)
    return [{
      json: {
        success: false,
        error: error.message,
        validationStatus: 'failed',
        timestamp: new Date().toISOString()
      }
    }];
  }
}

return validatedItems;

const items = $input.all();
const output = [];

function parseTextWithTable(text) {
  const lines = text
    .split("\n")
    .map(l => l.trim())
    .filter(Boolean);

  const headerKeywords = [
    "GPO",
    "Product",
    "Vendor",
    "Category",
    "Sub-Category",
    "Price",
    "Quantity",
    "Discount",
    "Admin Fees",
    "Expiration",
    "Contract Name",
    "Contract Type"
  ];

  let tableStartIndex = lines.findIndex(line =>
    headerKeywords.some(h => line.includes(h))
  );

  if (tableStartIndex === -1) {
    return {
      tableFound: false,
      readableText: text,
      tableData: []
    };
  }

  // Skip header rows (usually 2–4 lines)
  const readableText = lines.slice(0, tableStartIndex).join("\n");
  const tableLines = lines.slice(tableStartIndex + 3);

  const tableData = [];
  let row = {};

  for (const line of tableLines) {
    if (/^\d{4}-\d{2}-\d{2}$/.test(line)) {
      row.Expiration = line;
      continue;
    }

    if (/Contract/i.test(line)) {
      row.ContractName = line;
      continue;
    }

    if (/^(National|Regional)$/i.test(line)) {
      row.ContractType = line;

      // Row complete → push
      if (Object.keys(row).length > 5) {
        tableData.push(row);
      }
      row = {};
      continue;
    }

    if (!row.GPO) row.GPO = line;
    else if (!row.Product) row.Product = line;
    else if (!row.Vendor) row.Vendor = line;
    else if (!row.Category) row.Category = line;
    else if (!row.SubCategory) row.SubCategory = line;
    else if (!row.Price && !isNaN(line)) row.Price = Number(line);
    else if (!row.Quantity && !isNaN(line)) row.Quantity = Number(line);
    else if (!row.DiscountPercent && !isNaN(line)) row.DiscountPercent = Number(line);
    else if (!row.AdminFeesPercent && !isNaN(line)) row.AdminFeesPercent = Number(line);
  }

  return {
    tableFound: true,
    readableText,
    tableData
  };
}

for (const item of items) {
