const items = $input.all();
const output = [];

function repairOCRText(rawText) {
  let text = rawText;

  text = text.replace(/([A-Za-z])\n([a-z])/g, "$1$2");
  text = text.replace(/-\n/g, "");

  text = text.replace(/(\d+)\n\.(\d)\n(\d+)/g, "$1.$2$3");
  text = text.replace(/(\d+)\n(\d{1,3})(?!\.)/g, "$1$2");
  text = text.replace(/(\d+)\n\.(\d+)/g, "$1.$2");

  text = text.replace(/(\d{3})\n(\d{1})-(\d{2})\n-(\d{2})/g, "$1$2-$3-$4");

  text = text.replace(/Natio\nnal/g, "National");
  text = text.replace(/Regio\nnal/g, "Regional");

  const headerFixes = {
    "Pro\nduct": "Product",
    "Sub-c\natego\nry": "Sub-Category",
    "Categor\ny": "Category",
    "Qu\nant\nity": "Quantity",
    "Pri\nce": "Price",
    "Disc\nount": "Discount",
    "Admin\nFees": "Admin Fees",
    "Expi\nratio\nn": "Expiration",
    "Contr\nact\nType": "Contract Type"
  };

  for (const broken in headerFixes) {
    text = text.replace(new RegExp(broken, "g"), headerFixes[broken]);
  }

  return text.replace(/\n{2,}/g, "\n").trim();
}

for (const item of items) {
  const rawText = item.json?.text;

  if (!rawText) {
    output.push({ json: { error: "No text found" } });
    continue;
  }


  output.push({
    json: {
      repairedText: repairOCRText(rawText),

    }
  });
}

return output;

const items = $input.all();
const results = [];

for (const item of items) {
  const text = item.json?.cleanedText || '';

  if (!text) {
    item.json.txtError = 'No readableText available';
    results.push(item);
    continue;
  }

  const filename = $('File Validation').first().json.fileName;

  const header = 
`========================================
Extracted from: ${filename}
Extraction Date: ${new Date().toISOString()}
========================================

`;

  const fullText = header + text;

  const txtBuffer = Buffer.from(fullText, 'utf-8');

  item.binary = item.binary || {};
  item.binary.txtFile = {
    data: txtBuffer.toString('base64'),
    mimeType: 'text/plain',
    fileName: filename.replace('.pdf', '') + '_extracted.txt',
    fileExtension: 'txt',
    fileSize: txtBuffer.length
  };

  item.json.txtCreated = true;
  results.push(item);
}

return results;

const items = $input.all();
const results = [];

function tableDataToCSV(tableData) {
  if (!tableData.length) return '';

  const headers = Object.keys(tableData[0]);
  const csvRows = [];

  csvRows.push(headers.join(','));

  for (const row of tableData) {
    const values = headers.map(h => {
      const value = row[h] ?? '';
      const escaped = String(value).replace(/"/g, '""');
      return `"${escaped}"`;
    });
    csvRows.push(values.join(','));
  }

  return csvRows.join('\n');
}

function textToSingleColumnCSV(text) {
  const lines = text.split('\n').filter(Boolean);
  const csv = ['LineNumber,Content'];

  lines.forEach((line, i) => {
    csv.push(`${i + 1},"${line.replace(/"/g, '""')}"`);
  });

  return csv.join('\n');
}

for (const item of items) {
  const tableData = item.json?.tableData || [];
  const readableText = item.json?.readableText || '';

  let csvContent = '';
  let method = '';

  if (tableData.length > 0) {
    csvContent = tableDataToCSV(tableData);
    method = 'structured-table';
  } else {
    csvContent = textToSingleColumnCSV(readableText);
    method = 'text-fallback';
  }

  const csvBuffer = Buffer.from(csvContent, 'utf-8');
  const filename = $('File Validation').first().json.fileName;

  item.binary = item.binary || {};
  item.binary.csvFile = {
    data: csvBuffer.toString('base64'),
    mimeType: 'text/csv',
    fileName: filename.replace('.pdf', '') + '_extracted.csv',
    fileExtension: 'csv',
    fileSize: csvBuffer.length
  };

  item.json.csvCreated = true;
  item.json.csvConversionMethod = method;
  item.json.csvRowCount = csvContent.split('\n').length;

  results.push(item);
}

return results;
